module top_module(
    input [3:0] bin,
    output reg [2:0] mod_dec
);always @(*) begin
    case(bin)
        4'b0000: mod_dec = 3'b000;
        4'b0001: mod_dec = 3'b001;
        4'b0010: mod_dec = 3'b010;
        4'b0011: mod_dec = 3'b011;
        4'b0100: mod_dec = 3'b100;
        4'b0101: mod_dec = 3'b101;
        4'b0110: mod_dec = 3'b110;
        4'b0111: mod_dec = 3'b111;
        4'b1000: mod_dec = 3'b000;
        4'b1001: mod_dec = 3'b001;
        4'b1010: mod_dec = 3'b010;
        4'b1011: mod_dec = 3'b011;
        4'b1100: mod_dec = 3'b100;
        4'b1101: mod_dec = 3'b101;
        4'b1110: mod_dec = 3'b110;
        4'b1111: mod_dec = 3'b111;
    endcase
end

endmodule
